import {PRESET_LABELS} from '../state/texture-presets.js';import {RECIPES} from './recipes.js';
export function attachControls(el,app){const presets=Object.entries(PRESET_LABELS).map(([k,v])=>`<button data-p='${k}'>${v}</button>`).join('');const recipes=Object.keys(RECIPES).map(n=>`<option>${n}</option>`).join('');el.innerHTML=`<details open><summary>Tessera Lab</summary><div>${presets}</div><select id='recipe'>${recipes}</select>${slider('intensity',.25,2.5,0.01,1)}${slider('motion',.25,3,0.01,1)}${slider('spectral',.25,2.5,0.01,1)}${slider('filament',0,2.5,0.01,1)}${slider('event',.5,2.5,0.01,1)}${slider('density',.5,2,0.01,1)}<div class='row'><button data-act='pause'>Pause</button><button data-act='capture'>Capture</button><button data-act='copy'>Copy Debug</button><button data-act='slow'>SlowMo</button></div></details>`;
el.onclick=(e)=>{const b=e.target.closest('button');if(!b)return;if(b.dataset.p)app.setPreset(b.dataset.p);if(b.dataset.act)app.action(b.dataset.act)};
el.querySelector('#recipe').onchange=e=>app.setRecipe(e.target.value);
[['intensity','setIntensity'],['motion','setMotionBoldness'],['spectral','setSpectralStrength'],['filament','setFilamentStrength'],['event','setEventTheatre'],['density','setDensity']].forEach(([id,m])=>el.querySelector('#'+id).oninput=e=>app[m](+e.target.value));}
const slider=(id,min,max,step,val)=>`<label>${id}<input id='${id}' type='range' min='${min}' max='${max}' step='${step}' value='${val}'/></label>`;
